INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06420', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「丈口碑在民，公論在上，些小觸忤，何足芥蒂！且丈夫各行其志耳。烏紗擲與優 人，青袍改作裙褌，角帶毀為糞箕。但辨此心，天下事何不可為？安能俯首低眉， 向人覓顏色哉！丈負大有用之姿，具大有為之才，小小嫌疑，如洪爐上一點雪耳。 無為禍始，無為福先，無為名尸。珍重！」根據上引袁宏道〈與聶化南〉一文，下 列敘述最不適切的選項是： 由信中可知聶化南在公務上稍有不順遂 「洪爐上一點雪耳」，指沒有影響、不足為道 「烏紗擲與優人」三句，意謂官場如戲，不必認真 「俯首低眉，向人覓顏色」，指低聲下氣、討好他人', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06421', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「弈之優劣有定也。一著之失，人皆見之，雖護前者不能諱也。理之所在，各是其 所是，各非其所非，世無孔子，誰能定是非之真？然則人之失者，未必非得也；吾 之無失者，未必非大失也。而彼此相嗤無有已時，曾觀弈者之不若已。」（錢大昕 〈弈喻〉）下列選項，何者最接近本文意旨 世事雖然複雜，但真理愈辯愈明 為人處世應擇善固執，亦當從善如流 是非對錯一時難以驗證，互相指責並無意義 人生如棋，不能避免犯錯，故不必苛責他人之失', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06422', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '天子一見李白，如貧得富，如暗得燈，如飢得食，如旱得雲。開金口，宣玉音道： 「今有番國齎書，無人能曉，特宣卿至，為朕分憂。」白躬身奏道：「臣因學淺， 被太師批卷不中，高太尉將臣推搶出去。今有番書，何不令試官回答，卻乃久滯番 官在此？臣是被黜秀才，不能稱試官之意，怎能稱皇上之意？」天子道：「朕自知 卿，卿其勿辭！」（〈李太白醉草嚇蠻書〉）根據上文，下列敘述何者正確？ 李白曾因拒譯番國文書而得罪當朝權臣 李白恃才傲物，令想重用他的天子失望 天子勸李白莫因與當朝權臣不合而辭官 天子希望李白發揮所長，譯出番國文書', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06423', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '邑西白家莊，居民某，盜鄰鴨烹之。至夜，覺膚癢；天明視之，茸生鴨毛，觸之則 痛。大懼，無術可醫。夜夢一人告之曰：「汝病乃天罰，須得失者罵，毛乃可落。」 而鄰翁素雅量，生平失物，未嘗徵於聲色。某詭告翁曰：「鴨乃某甲所盜，彼深畏 罵，罵之亦可警將來。」翁笑曰：「誰有閒氣罵惡人。」卒不罵。某盜窘，因實告 鄰翁。翁乃罵，其病良已。異史氏曰：「甚矣，攘者之可懼也，一攘而鴨毛生；甚 矣，罵者之宜戒也，一罵而盜罪減；然為善有術，彼鄰翁者，是以罵行其慈者也。」 （蒲松齡〈罵鴨〉）下列何者最貼近老翁的為人？ 寬大為懷  不造口業  以德報怨  慢藏誨盜', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06424', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列那一個選項的警語，其意旨和其他三者不同？ 毀滅不了我的，只會使我更堅強 只要努力尋找，痛苦總會有意義的 只有敵人才會給我們鍛鍊耐性的機會 期望過高卻無堅實的基礎，那帶來的會是煩惱', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06425', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「建築而要把空氣隔絕於外，把光隔絕於外，甚至把人聲市語隔絕於外，是與商人 勾結的結果。為的是促銷空氣調節器，「日光」燈，音響，甚至便於思想控制—因 為可以播放你要播放的東西。」（孟祥森〈天何言哉〉）下列何者不在上文的批評 範圍內？ 人與自然二分  商業凌駕一切  恣意破壞生態  人與外界疏離', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06426', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「文學是一種高貴的、難纏的病，它會主動尋找宿主。體質敏感的宿主，會早早發 作。但有些人年紀大了之後，病情會減輕，乃致完全痊癒為『正常』—眼睛正常了、 思想正常了，可這人也變得乏味無趣了。」（顏艾琳〈文學病〉）關於本文，下列 敘述何者錯誤？ 由本文可見作者對於文學的執著，以及文學與生活密不可分的美妙連結關係 由本文可見作者對文學好惡的對比，隨著時間淡化的病症，渴望正常平凡生活的 到來 一個染了文學病的人，看世界的角度和思考事情的方式，會和正常人不同，但是 其生活絕不乏味 完全痊癒為「正常」—眼睛正常了、思想正常了，但生活也變得乏味無趣，是因 為生活中缺少了文學', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06427', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「我踢著鋁罐上學，踢著鋁罐放學，路邊的空鋁罐天天陪著我。它聽過我唱歌，知 道我為什麼難過，還看過我和別人打架，委屈掉淚。我對它說過的祕密，它永遠替 我保密。我對它說笑話，它就鏗鏗鏘鏘地滾到遠處去大笑。」下列何者最能表現這 段文字的主題： 童心的描述  寂寞的滋味  保密的珍貴  守信的重要 請依下文回答第17題至第18題： 我們都同意：好的東西，要與好朋友分享；因此，咖啡可以分享，音樂可以分享。 但是，唯有孤獨是不能與人分享的。若要欣賞孤獨的好處，首先必須知道它與寂寞不同。 「寂寞是一種冷冷清清的感覺，好像自己被別人遺棄了、被世界遺棄了、被生命遺棄了。 這種被遺棄的感覺往往出於主觀的幻想。自己把門窗關起來，然後抱怨沒有陽光。」孤 獨則不同，它使人暫時擺脫種種俗世的念慮，親親切切的面對自己，讓心中的旋律恣意 鳴奏，然後譜出寧靜悠遠的雅趣。更重要的是：孤獨往往牽引出沉思的心境，由沉思可 能帶來徹悟，煥發內在的光明，燭照人生的真義。唯有善於享受孤獨的人，才能分辨也 才會珍惜人與人之間交會時互放的光亮。（傅佩榮〈孤獨〉）', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06428', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '依上文，作者對寂寞的看法與下列何者相似？ 寂寞是寧靜的前奏  寂寞與孤獨常相伴而行 寂寞有著強烈被遺棄的感受  寂寞是客觀上孤單、自我封閉的感覺', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06429', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詩句，何者與傅佩榮的「孤獨」相類似？ 花間一壺酒，獨酌無相親。舉杯邀明月，對影成三人 出門搔白首，若負平生志。冠蓋滿京華，斯人獨憔悴 人歸山郭暗，雁下蘆洲白。獨夜憶秦關，聽鐘未眠客 一種相思，兩處閒愁。此情無計可消除，才下眉頭，却上心頭 請依下文回答第19題至第20題： 「張李成，臺灣內山人，美丰姿，操俳優業，媚目巧笑，傅脂粉登場，初不審其為 勇士也。光緒乙酉，法人攻臺北，觀察李某以劉省三中丞命，練士兵拒敵。張忽舍所業 應選，李呼張小字曰：『阿火，汝胡解兵事！』張慷慨言曰：『火生長是間，不欲變服 飾為西人奴也。』山中善火者可千人，招之立集，善獵能槍，可應敵。李善之，易其名 曰李成，謂李氏所成就者也。時擢勝軍二千眾，屯滬尾炮臺坡，李成則率新卒五百，分 為兩隊，承其後。擢勝軍一與敵接，立敗，張以二百五十人出，散髮赤身，嚼檳榔，紅 沫出其吻。時潮上，法人爭以小船抵坡下，坡上草深沒人。此二百五十人者見敵皆仰臥， 翹其左足，張趾架槍以待敵。敵近，二百五十槍齊發，法人死者百數。大駭而遁。山後 復出二百五十人，作圓陣包敵。時潮落舟膠，有巨賈購得法華戰事股票，從軍觀勝敗， 時亦陷足泥中。船上張白麾，請以金贖，張不可，作俳優聲曰：『吾不欲仇人金也。』 殺而烹其屍。」（《清稗類鈔．張李成》）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
